#include <hip/hip_runtime.h>
#include <stdio.h>
#include <stdint.h>
#include <chrono>

// Add a volatile sink write to prevent dead code elimination
static __global__ __launch_bounds__(256)
void read_kernel2(const float* __restrict__ src, float* sink, size_t n)
{
    size_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = gridDim.x * blockDim.x;
    float s = 0.0f;
    for (size_t i = tid; i < n; i += stride) {
        s += src[i];
        s += src[i];
    }
    if (tid == 0) *sink = s;
}

int main() {
    hipSetDevice(0);

    size_t buf_bytes = 4ULL * 1024 * 1024 * 1024;
    size_t n = buf_bytes / sizeof(float);

    float *d;
    hipMalloc(&d, buf_bytes);
    hipMemset(d, 0, buf_bytes);
    hipDeviceSynchronize();

    float *dsink;
    hipMalloc(&dsink, sizeof(float));

    int blocks = 512, threads = 256;

    hipLaunchKernelGGL(read_kernel2, dim3(blocks), dim3(threads), 0, 0, d, dsink, n);
    hipDeviceSynchronize();

    for (int iter = 0; iter < 3; iter++) {
        auto t0 = std::chrono::high_resolution_clock::now();
        hipLaunchKernelGGL(read_kernel2, dim3(blocks), dim3(threads), 0, 0, d, dsink, n);
        hipDeviceSynchronize();
        auto t1 = std::chrono::high_resolution_clock::now();
        double us = std::chrono::duration<double, std::micro>(t1 - t0).count();
        double bw = (double)buf_bytes / (us * 1e-6) / 1e9;
        printf("iter %d: %.0f us, BW=%.0f GB/s\n", iter, us, bw);
    }

    printf("sink=%f\n", dsink[0]);

    hipFree(d);
    hipFree(dsink);
    return 0;
}
