#include <hip/hip_runtime.h>
#include <stdio.h>
#include <chrono>
#include <algorithm>
#include <vector>

static __global__ void init_kernel(float4* p, size_t n)
{
    size_t i = blockIdx.x * blockDim.x + threadIdx.x;
    for (; i < n; i += gridDim.x * blockDim.x)
        p[i] = make_float4((float)(i*4), (float)(i*4+1), (float)(i*4+2), (float)(i*4+3));
}

static __global__ __launch_bounds__(256)
void read_f4(const float4* __restrict__ src, float* sink, size_t n)
{
    size_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = gridDim.x * blockDim.x;
    float s = 0.0f;
    for (size_t i = tid; i < n; i += stride) {
        float4 v = src[i];
        s += v.x + v.y + v.z + v.w;
    }
    if (tid == 0) *sink = s;
}

int main() {
    hipSetDevice(0);

    size_t buf_bytes = 4ULL * 1024 * 1024 * 1024;
    size_t nf4 = buf_bytes / sizeof(float4);

    float4 *d;
    hipMalloc(&d, buf_bytes);
    hipDeviceSynchronize();

    // Fill data using host-initiated memset with non-zero pattern
    // Use a separate kernel to init
    hipLaunchKernelGGL(init_kernel, dim3(4096), dim3(256), 0, 0, d, nf4);
    hipDeviceSynchronize();

    float *dsink;
    hipMalloc(&dsink, sizeof(float));
    hipMemset(dsink, 0, sizeof(float));

    int blocks = 512, threads = 256;
    int num_dispatches = 32;

    hipLaunchKernelGGL(read_f4, dim3(blocks), dim3(threads), 0, 0, d, dsink, nf4);
    hipDeviceSynchronize();

    std::vector<double> times;
    times.reserve(num_dispatches);

    for (int i = 0; i < num_dispatches; i++) {
        auto t0 = std::chrono::high_resolution_clock::now();
        hipLaunchKernelGGL(read_f4, dim3(blocks), dim3(threads), 0, 0, d, dsink, nf4);
        hipDeviceSynchronize();
        auto t1 = std::chrono::high_resolution_clock::now();
        times.push_back(std::chrono::duration<double>(t1 - t0).count());
    }

    float h_sink;
    hipMemcpy(&h_sink, dsink, sizeof(float), hipMemcpyDeviceToHost);
    printf("sink = %e\n", h_sink);

    std::sort(times.begin(), times.end());
    double med = times[num_dispatches / 2];
    double bw = (double)buf_bytes / med / 1e9;

    printf("HBM_BANDWIDTH_GBPS=%.1f\n", bw);
    printf("buffer_bytes=%zu\n", buf_bytes);

    hipFree(d);
    hipFree(dsink);
    return 0;
}
EOF
